import{_ as a,o as i,c as o,a3 as t}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"Notely User Guide","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide.md","filePath":"user-guide.md","lastUpdated":1784606116000}'),r={name:"user-guide.md"};function l(n,e,s,d,c,p){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="notely-user-guide" tabindex="-1">Notely User Guide <a class="header-anchor" href="#notely-user-guide" aria-label="Permalink to &quot;Notely User Guide&quot;">​</a></h1><p>Use this guide for everyday work in Notely: creating notes, editing safely, finding information quickly, and working with visuals.</p><h2 id="_1-set-up-your-workspace" tabindex="-1">1. Set Up Your Workspace <a class="header-anchor" href="#_1-set-up-your-workspace" aria-label="Permalink to &quot;1. Set Up Your Workspace&quot;">​</a></h2><ol><li>Open Notely.</li><li>Go to <strong>File -&gt; Open Workspace</strong>.</li><li>Select the folder where your notes should live.</li><li>Confirm and continue.</li></ol><p>Result: your notes and folders appear in the main list.</p><p>Tip: use <strong>File -&gt; Open Recent</strong> when you want to jump back into a recently used workspace faster.</p><h2 id="_2-create-and-organize-notes" tabindex="-1">2. Create and Organize Notes <a class="header-anchor" href="#_2-create-and-organize-notes" aria-label="Permalink to &quot;2. Create and Organize Notes&quot;">​</a></h2><ol><li>Create a note from <strong>File -&gt; New Note</strong> (<code>Ctrl/Cmd + N</code>).</li><li>Create folders to group related notes.</li><li>Use clear titles and optional tags so notes are easier to find later.</li></ol><h2 id="_3-write-and-edit-faster" tabindex="-1">3. Write and Edit Faster <a class="header-anchor" href="#_3-write-and-edit-faster" aria-label="Permalink to &quot;3. Write and Edit Faster&quot;">​</a></h2><p>Choose the view mode that fits your task:</p><ul><li><code>Edit</code>: write raw markdown.</li><li><code>Split</code>: write and preview side-by-side.</li><li><code>Preview</code>: read final output.</li></ul><p>Helpful actions:</p><ul><li>Find text: <code>Ctrl/Cmd + F</code></li><li>Use toolbar buttons for headings, lists, links, tables, and diagrams.</li><li>Edit markdown tables inline by placing the cursor inside a table and using the popup grid controls. <ul><li>Add/remove rows and columns from compact action chips.</li><li>Adjust column alignment from header controls.</li><li>Save with <strong>Save</strong>, or close/cancel with <strong>Cancel</strong> or <code>Esc</code>.</li></ul></li><li>Format code blocks automatically and use the dedicated code editor popup.</li><li>Fix issues shown by markdown validation and typo checks.</li></ul><h2 id="_4-recover-changes-with-git-version-control" tabindex="-1">4. Recover Changes with Git Version Control <a class="header-anchor" href="#_4-recover-changes-with-git-version-control" aria-label="Permalink to &quot;4. Recover Changes with Git Version Control&quot;">​</a></h2><p>Notely tracks your document history with a native Git-backed system:</p><ol><li>Open <strong>Version Control -&gt; History</strong> (<code>Ctrl/Cmd + Shift + H</code>) or click the <strong>History</strong> button in the top menu of an open note.</li><li>Select a commit from the timeline list to inspect its details.</li><li>Compare commits or restore a note to that version.</li><li>Add tags directly to commits to bookmark key milestones.</li></ol><p>Use this to track changes chronologically and recover older revisions of any note.</p><h2 id="_5-work-with-images-and-files" tabindex="-1">5. Work with Images and Files <a class="header-anchor" href="#_5-work-with-images-and-files" aria-label="Permalink to &quot;5. Work with Images and Files&quot;">​</a></h2><p>You can insert and manage media directly from your notes:</p><ul><li>Add images and linked files.</li><li>Rename or replace existing media.</li><li>Open media in the default app.</li><li>Use image tools like crop and annotation when needed.</li></ul><p>Tip: keep image names meaningful so teammates can identify assets quickly.</p><h2 id="_6-capture-screen-areas-into-notes-windows" tabindex="-1">6. Capture Screen Areas into Notes (Windows) <a class="header-anchor" href="#_6-capture-screen-areas-into-notes-windows" aria-label="Permalink to &quot;6. Capture Screen Areas into Notes (Windows)&quot;">​</a></h2><ol><li>Place your cursor where you want the screenshot markdown inserted.</li><li>Click the toolbar capture icon, or press <code>Ctrl/Cmd + Shift + S</code>.</li><li>Select screen area in Windows snip overlay.</li><li>If mode is <strong>Auto Insert</strong>, image is inserted directly.</li><li>If mode is <strong>Review Before Insert</strong>, adjust (optional) and click <strong>Save</strong>.</li></ol><p>Change mode in <strong>Settings -&gt; Screen Capture</strong>.</p><p>Tip: capture icon marker shows active mode (<code>A</code> auto, <code>R</code> review).</p><h2 id="_7-use-diagrams-mermaid-and-excalidraw" tabindex="-1">7. Use Diagrams (Mermaid and Excalidraw) <a class="header-anchor" href="#_7-use-diagrams-mermaid-and-excalidraw" aria-label="Permalink to &quot;7. Use Diagrams (Mermaid and Excalidraw)&quot;">​</a></h2><h3 id="mermaid" tabindex="-1">Mermaid <a class="header-anchor" href="#mermaid" aria-label="Permalink to &quot;Mermaid&quot;">​</a></h3><ol><li>Insert a Mermaid block from the toolbar.</li><li>Write Mermaid syntax.</li><li>Check rendering in <code>Split</code> or <code>Preview</code>.</li></ol><h3 id="excalidraw" tabindex="-1">Excalidraw <a class="header-anchor" href="#excalidraw" aria-label="Permalink to &quot;Excalidraw&quot;">​</a></h3><ol><li>Insert an Excalidraw diagram.</li><li>Edit visually and save.</li><li>Re-open from preview to continue editing.</li></ol><h3 id="convert-an-image-to-excalidraw" tabindex="-1">Convert an image to Excalidraw <a class="header-anchor" href="#convert-an-image-to-excalidraw" aria-label="Permalink to &quot;Convert an image to Excalidraw&quot;">​</a></h3><ol><li>In preview, right-click a workspace image.</li><li>Select <strong>Edit with Excalidraw</strong>.</li><li>Draw on top of the image (the starting image is resizable on canvas).</li><li>Save diagram to replace the markdown image reference.</li></ol><h3 id="restore-original-image-from-converted-diagram" tabindex="-1">Restore original image from converted diagram <a class="header-anchor" href="#restore-original-image-from-converted-diagram" aria-label="Permalink to &quot;Restore original image from converted diagram&quot;">​</a></h3><ol><li>Right-click an Excalidraw preview created from an image.</li><li>Select <strong>Restore original image</strong>.</li></ol><p>Note: restore appears only for diagrams that were created from an image conversion flow.</p><h2 id="_8-navigate-large-workspaces" tabindex="-1">8. Navigate Large Workspaces <a class="header-anchor" href="#_8-navigate-large-workspaces" aria-label="Permalink to &quot;8. Navigate Large Workspaces&quot;">​</a></h2><ul><li><strong>View -&gt; Show Outline</strong> for quick jumps inside long notes.</li><li><strong>View -&gt; Split Preview</strong> to keep source and output aligned.</li><li><strong>View -&gt; Focus Mode</strong> to reduce distractions.</li><li><strong>Workspace -&gt; Workspace Graph</strong> to explore note and media relationships.</li></ul><h2 id="_9-track-tasks-across-notes" tabindex="-1">9. Track Tasks Across Notes <a class="header-anchor" href="#_9-track-tasks-across-notes" aria-label="Permalink to &quot;9. Track Tasks Across Notes&quot;">​</a></h2><p>Use markdown task checkboxes in your notes:</p><ul><li>Open task: <code>- [ ]</code></li><li>Completed task: <code>- [x]</code></li></ul><p>Then review tasks centrally:</p><ol><li>Open Command Palette (<code>Ctrl/Cmd + K</code>).</li><li>Run <strong>Open Tasks Panel</strong> for pending tasks.</li><li>Run <strong>Open All Tasks</strong> to view open + completed tasks.</li><li>Open the source note directly from a task row when you need context.</li></ol><h2 id="_10-export-workspace-as-zip" tabindex="-1">10. Export Workspace as Zip <a class="header-anchor" href="#_10-export-workspace-as-zip" aria-label="Permalink to &quot;10. Export Workspace as Zip&quot;">​</a></h2><ol><li>Go to the landing screen (notes list view).</li><li>Open <strong>File -&gt; Export Workspace as Zip</strong>.</li><li>Choose export format: <ul><li>Notes as-is (Markdown + assets)</li><li>PDF-only</li><li>Web format</li></ul></li><li>Choose whether to include Notely app data from <code>.notes-app</code> (default is off).</li><li>Select destination folder (Browse is available and last path is remembered).</li><li>Confirm or edit filename (default <code>notelyproject.zip</code>).</li><li>Click <strong>Export Zip</strong>.</li></ol><h2 id="_11-get-help-quickly" tabindex="-1">11. Get Help Quickly <a class="header-anchor" href="#_11-get-help-quickly" aria-label="Permalink to &quot;11. Get Help Quickly&quot;">​</a></h2><ul><li><strong>Help -&gt; Help Center</strong> (<code>F1</code>) for in-app help.</li><li><strong>Help -&gt; Keyboard Shortcuts</strong> (<code>Ctrl/Cmd + /</code>) for key bindings.</li><li><strong>Help -&gt; About Notely</strong> for app version details.</li></ul>',46)])])}const m=a(r,[["render",l]]);export{g as __pageData,m as default};
